import type { ButtonHTMLAttributes, PropsWithChildren } from "react";

import { cn } from "@/lib/utils";

type ButtonVariant = "primary" | "secondary" | "ghost" | "danger";
type ButtonSize = "sm" | "md" | "lg";

export function buttonStyles({
  variant = "primary",
  size = "md",
  className,
}: {
  variant?: ButtonVariant;
  size?: ButtonSize;
  className?: string;
}) {
  return cn(
    "inline-flex items-center justify-center rounded-full border text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent focus-visible:ring-offset-2 focus-visible:ring-offset-background disabled:cursor-not-allowed disabled:opacity-60",
    size === "sm" && "h-9 px-4",
    size === "md" && "h-10 px-5",
    size === "lg" && "h-11 px-6",
    variant === "primary" &&
      "border-accent bg-accent text-accent-foreground shadow-[0_10px_40px_rgba(56,189,248,0.24)] hover:bg-sky-400",
    variant === "secondary" &&
      "border-border bg-white/5 text-foreground hover:border-sky-400/40 hover:bg-white/10",
    variant === "ghost" &&
      "border-transparent bg-transparent text-muted-foreground hover:text-foreground",
    variant === "danger" &&
      "border-red-500/30 bg-red-500/10 text-red-200 hover:bg-red-500/20",
    className,
  );
}

export function Button({
  children,
  className,
  variant,
  size,
  ...props
}: PropsWithChildren<
  ButtonHTMLAttributes<HTMLButtonElement> & {
    variant?: ButtonVariant;
    size?: ButtonSize;
  }
>) {
  return (
    <button className={buttonStyles({ variant, size, className })} {...props}>
      {children}
    </button>
  );
}
